```json
{
  "global": "Navigate to a retail website, apply filters for best-selling black hoodies in men's Big and Tall size within a $25–$50 price range, and browse the resulting product listings.",
  "subtasks": [
    {
      "subtask": "Navigate to the men's hoodies category",
      "atomics": [
        "Open the retail website homepage",
        "Locate and click the 'Men' or 'Men's' department link in the main navigation",
        "Find and click the 'Sweatshirts & Hoodies' or equivalent subcategory link"
      ]
    },
    {
      "subtask": "Apply the color filter for Black",
      "atomics": [
        "Locate the 'Color' filter panel on the search/category results page",
        "Click or select 'Black' from the color options"
      ]
    },
    {
      "subtask": "Apply the size filter for Big and Tall",
      "atomics": [
        "Locate the 'Size' filter panel",
        "Select 'Big & Tall' or equivalent size category option"
      ]
    },
    {
      "subtask": "Apply the price range filter for $25–$50",
      "atomics": [
        "Locate the 'Price' filter panel",
        "Set the minimum price to $25 and the maximum price to $50",
        "Confirm or apply the price range filter"
      ]
    },
    {
      "subtask": "Sort results by best selling",
      "atomics": [
        "Locate the sort/order dropdown on the results page",
        "Select 'Best Selling' or 'Top Sellers' from the sort options"
      ]
    }
  ],
  "global_atomics": [
    "Verify the active filters displayed on the results page show: Color=Black, Size=Big & Tall, Price=$25–$50, Sort=Best Selling",
    "Confirm at least one product listing is visible in the filtered results"
  ],
  "gold_actions": {
    "global": "Use the site navigation and filter sidebar to sequentially select Men > Hoodies, Color=Black, Size=Big & Tall, Price=$25–$50, Sort=Best Selling and confirm filtered results load.",
    "subtasks": [
      {
        "subtask": "Navigate to the men's hoodies category",
        "atomics": [
          "Click the top-level 'Men' navigation menu item",
          "Click 'Sweatshirts & Hoodies' in the dropdown or left-rail category menu",
          "Wait for the hoodies category results page to load"
        ]
      },
      {
        "subtask": "Apply the color filter for Black",
        "atomics": [
          "Scroll to the 'Color' section in the left-rail filter panel",
          "Click the checkbox or swatch labeled 'Black' and wait for results to refresh"
        ]
      },
      {
        "subtask": "Apply the size filter for Big and Tall",
        "atomics": [
          "Scroll to the 'Size' section in the filter panel",
          "Click 'Big & Tall' size option and wait for results to refresh"
        ]
      },
      {
        "subtask": "Apply the price range filter for $25–$50",
        "atomics": [
          "Scroll to the 'Price' filter section",
          "Enter '25' in the min price input and '50' in the max price input",
          "Click 'Go' or 'Apply' to submit the price range and wait for results to refresh"
        ]
      },
      {
        "subtask": "Sort results by best selling",
        "atomics": [
          "Click the sort-order dropdown (e.g., labeled 'Sort By')",
          "Select 'Best Selling' from the dropdown options and wait for results to reorder"
        ]
      }
    ],
    "global_atomics": [
      "Read the active filter tags/breadcrumbs at the top of results to confirm all four filters (Black, Big & Tall, $25–$50, Best Selling) are applied simultaneously",
      "Assert that the product grid displays at least one hoodie item with a price in the $25–$50 range"
    ]
  }
}
```
